import { Component } from '@angular/core';
import { ChatService } from '../services/chat.service';

@Component({
  selector: 'app-chat',
  templateUrl: './chat.component.html',
  styleUrls: ['./chat.component.scss']
})
export class ChatComponent {

  messages: string[] = [];
  userMessage: string = '';


  constructor(private chatService: ChatService) {}

  input_text: string = '';

  prompt: string = '';
  istyping: boolean = false;
  isPlaying: boolean = false;


    topics = [
        { title: 'Тема 1', description: 'Описание темы 1' },
        { title: 'Тема 2', description: 'Описание темы 2' }
    ];



  sendMessage() {
    if (!this.input_text.trim() || this.isPlaying) {
      this.input_text='';
      console.log(1);
      return;
    }

    this.topics.push({ title: this.input_text, description: 'Описание для ' + this.input_text });        
    console.log(2);
    this.input_text='';
  }

  openDialog(fullResponse: string) {
    alert(fullResponse); // Здесь можно использовать более сложный диалог, например, модальное окно
}
}
